template<typename T>
void rgbToComponents(T *d_r, T *d_g, T *d_b, unsigned char *src, int width, int height) {
    int pixels = width * height;
    int alignedSize = DIVANDRND(width * height, THREADS) * THREADS * 3;

    unsigned char *d_src = nullptr;
    cudaMalloc(&d_src, pixels * 3);
    cudaMemcpy(d_src, src, pixels * 3, cudaMemcpyHostToDevice);

    int globalThreads = alignedSize / 3;
    int blocks = DIVANDRND(globalThreads, THREADS);

    if constexpr (std::is_same<T, int>::value) {
        c_CopySrcToComponents_int<<<blocks, THREADS>>>(d_r, d_g, d_b, d_src, pixels);
    } else {
        c_CopySrcToComponents_float<<<blocks, THREADS>>>(d_r, d_g, d_b, d_src, pixels);
    }
    cudaFree(d_src);
}

