    unsigned char *d_src = nullptr;
    cudaMalloc(&d_src, pixels);
    cudaMemcpy(d_src, src, pixels, cudaMemcpyHostToDevice);

    int globalThreads = alignedSize / 9; // preserved from source
    int blocks = DIVANDRND(globalThreads, THREADS);

    if constexpr (std::is_same<T, int>::value) {
        c_CopySrcToComponent_int<<<blocks, THREADS>>>(d_c, d_src, pixels);
    } else {
        c_CopySrcToComponent_float<<<blocks, THREADS>>>(d_c, d_src, pixels);
    }
