// ---- FDWT53 kernel port ----

struct VerticalDWTPixelIO {
    bool CHECKED;
    int end, stride;
};
struct VerticalDWTPixelLoader {
    bool CHECKED;
    int last;
};
struct VerticalDWTBandIO {
    bool CHECKED;
    int end;
    int strideHighToLow;
    int strideLowToHigh;
};
struct VerticalDWTBandWriter {
    bool CHECKED;
    int next;
};
struct TransformBuffer {
    int SIZE_X, SIZE_Y;
    int VERTICAL_STRIDE;
    int SHM_BANKS, BUFFER_SIZE, PADDING, ODD_OFFSET;
    int data[2182];
};
struct FDWT53Column {
    bool CHECKED_LOADER;
    VerticalDWTPixelLoader loader;
    int offset;
    int pixel0, pixel1, pixel2;
};
struct FDWT53 {
    int WIN_SIZE_X, WIN_SIZE_Y;
    FDWT53Column column;
    TransformBuffer buffer;
    int STRIDE;
};

__device__ static inline void mirror_i(int *d, const int sizeD) {
    if ((*d) >= sizeD) *d = 2 * sizeD - 2 - (*d);
    else if ((*d) < 0) *d = -(*d);
}
__device__ static inline int initialize_PixelIO(VerticalDWTPixelIO *pIO, bool CHECK, int sizeX, int sizeY, int firstX, int firstY) {
    pIO->CHECKED = CHECK;
    pIO->end = pIO->CHECKED ? (sizeY * sizeX + firstX) : 0;
    pIO->stride = sizeX;
    return firstX + sizeX * firstY;
}
__device__ static inline void init_PixelLoader(VerticalDWTPixelLoader *loader, int sizeX, int sizeY, int firstX, int firstY, VerticalDWTPixelIO *pIO, bool CHECK) {
    mirror_i(&firstX, sizeX);
    loader->last = initialize_PixelIO(pIO, CHECK, sizeX, sizeY, firstX, firstY) - sizeX;
}
__device__ static inline void clear_PixelLoader(VerticalDWTPixelLoader *pLoader, VerticalDWTPixelIO *pIO) {
    pLoader->last = 0; pIO->end = 0; pIO->stride = 0;
}
__device__ static inline int loadFrom(VerticalDWTPixelLoader *pLoader, const int *input, VerticalDWTPixelIO *pIO, int CHECK) {
    pLoader->last += pIO->stride;
    if (CHECK && (pLoader->last == pIO->end)) {
        pLoader->last -= 2 * pIO->stride;
        pIO->stride = -pIO->stride;
    }
    return input[pLoader->last];
}
__device__ static inline int initialize_BandIO(VerticalDWTBandIO *bandIO, int imageSizeX, int imageSizeY, int firstX, int firstY) {
    int columnOffset = firstX / 2;
    int verticalStride;
    if (firstX & 1) {
        verticalStride = imageSizeX / 2;
        columnOffset += divRndUp_int(imageSizeX, 2) * divRndUp_int(imageSizeY, 2);
        bandIO->strideLowToHigh = (imageSizeX * imageSizeY) / 2;
    } else {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        bandIO->strideLowToHigh = divRndUp_int(imageSizeY, 2) * imageSizeX;
    }
    bandIO->strideHighToLow = verticalStride - bandIO->strideLowToHigh;
    if (bandIO->CHECKED) {
        bandIO->end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * bandIO->strideLowToHigh;
    } else {
        bandIO->end = 0;
    }
    return columnOffset + (firstY / 2) * verticalStride + (firstY & 1) * bandIO->strideLowToHigh;
}
__device__ static inline int saveAndUpdate(VerticalDWTBandWriter *writer, bool CHECK, VerticalDWTBandIO *bandIO, int *output, int *item, int *stride) {
    writer->CHECKED = CHECK;
    if ((!writer->CHECKED) || (writer->next != bandIO->end)) {
        output[writer->next] = *item;
        writer->next += *stride;
    }
    return writer->next;
}
__device__ static inline void clear_BandWriter(VerticalDWTBandWriter *writer, VerticalDWTBandIO *bandIO) {
    bandIO->end = 0; bandIO->strideHighToLow = 0; bandIO->strideLowToHigh = 0; writer->next = 0;
}
__device__ static inline void init_BandWriter(VerticalDWTBandWriter *writer, VerticalDWTBandIO *bandIO, int imageSizeX, int imageSizeY, int firstX, int firstY) {
    if (firstX < imageSizeX) writer->next = initialize_BandIO(bandIO, imageSizeX, imageSizeY, firstX, firstY);
    else clear_BandWriter(writer, bandIO);
}
__device__ static inline int writeLowInto(VerticalDWTBandWriter *writer, VerticalDWTBandIO *bandIO, int *output, int *primary) {
    return saveAndUpdate(writer, writer->CHECKED, bandIO, output, primary, &(bandIO->strideLowToHigh));
}
__device__ static inline int writeHighInto(VerticalDWTBandWriter *writer, VerticalDWTBandIO *bandIO, int *output, int *other) {
    return saveAndUpdate(writer, writer->CHECKED, bandIO, output, other, &(bandIO->strideHighToLow));
}
__device__ static inline void horizontalStep(TransformBuffer *buffer, int count, int prevOffset, int midOffset, int nextOffset, int flag) {
    const int STEPS = count / buffer->SIZE_X;
    const int finalCount = count % buffer->SIZE_X;
    const int finalOffset = count - finalCount;
    for (int i = 0; i < STEPS; i++) {
        const int previous = buffer->data[prevOffset + i * buffer->SIZE_X + threadIdx.x];
        const int next = buffer->data[nextOffset + i * buffer->SIZE_X + threadIdx.x];
        int *center = &(buffer->data[midOffset + i * buffer->SIZE_X + threadIdx.x]);
        if (flag == 0) *center -= (previous + next) / 2;
        else if (flag == 1) *center += (previous + next + 2) / 4;
    }
    if (threadIdx.x < finalCount) {
        const int previous = buffer->data[prevOffset + finalOffset + threadIdx.x];
        const int next = buffer->data[nextOffset + finalOffset + threadIdx.x];
        int *center = &(buffer->data[midOffset + finalOffset + threadIdx.x]);
        if (flag == 0) *center -= (previous + next) / 2;
        else if (flag == 1) *center += (previous + next + 2) / 4;
    }
}
__device__ static inline void forEachHorizontalOdd(TransformBuffer *buffer, int firstLine, int numLines, int flag) {
    const int count = numLines * buffer->VERTICAL_STRIDE - 1;
    const int prevOffset = firstLine * buffer->VERTICAL_STRIDE;
    const int centerOffset = prevOffset + buffer->ODD_OFFSET;
    const int nextOffset = prevOffset + 1;
    horizontalStep(buffer, count, prevOffset, centerOffset, nextOffset, flag);
}
__device__ static inline void forEachHorizontalEven(TransformBuffer *buffer, int firstLine, int numLines, int flag) {
    const int count = numLines * buffer->VERTICAL_STRIDE - 1;
    const int centerOffset = firstLine * buffer->VERTICAL_STRIDE + 1;
    const int prevOffset = firstLine * buffer->VERTICAL_STRIDE + buffer->ODD_OFFSET;
    const int nextOffset = prevOffset + 1;
    horizontalStep(buffer, count, prevOffset, centerOffset, nextOffset, flag);
}
__device__ static inline void forEachVerticalOdd(TransformBuffer *buffer, int columnOffset, int flag) {
    int steps = (buffer->SIZE_Y - 1) / 2;
    for (int i = 0; i < steps; i++) {
        int row = i * 2 + 1;
        int prev = buffer->data[columnOffset + (row - 1) * buffer->VERTICAL_STRIDE];
        int next = buffer->data[columnOffset + (row + 1) * buffer->VERTICAL_STRIDE];
        if (flag == 0) buffer->data[columnOffset + row * buffer->VERTICAL_STRIDE] -= (prev + next) / 2;
    }
}
__device__ static inline void forEachVerticalEven(TransformBuffer *buffer, int columnOffset, int flag) {
    if (buffer->SIZE_Y > 3) {
        int steps = (int)(buffer->SIZE_Y / 2) - 1;
        for (int i = 0; i < steps; i++) {
            int row = 2 + i * 2;
            int prev = buffer->data[columnOffset + (row - 1) * buffer->VERTICAL_STRIDE];
            int next = buffer->data[columnOffset + (row + 1) * buffer->VERTICAL_STRIDE];
            if (flag == 1) buffer->data[columnOffset + row * buffer->VERTICAL_STRIDE] += (prev + next + 2) / 4;
        }
    }
}
__device__ static inline void clear_FDWT53Column(FDWT53Column *c, VerticalDWTPixelIO *pIO) {
    c->offset = 0; c->pixel0 = 0; c->pixel1 = 0; c->pixel2 = 0; clear_PixelLoader(&(c->loader), pIO);
}
__device__ static inline int getColumnOffset(int columnIndex, TransformBuffer *buffer) {
    columnIndex += BOUNDARY_X;
    return columnIndex / 2 + (columnIndex & 1) * buffer->ODD_OFFSET;
}
__device__ static inline void initColumn(FDWT53 *fdwt53, FDWT53Column *column, bool CHECKED, const int *input, int sizeX, int sizeY, int colIndex, int firstY, VerticalDWTPixelIO *pIO) {
    column->CHECKED_LOADER = CHECKED;
    column->offset = getColumnOffset(colIndex, &fdwt53->buffer);
    const int firstX = blockIdx.x * fdwt53->WIN_SIZE_X + colIndex;
    if (blockIdx.y == 0) {
        init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY, pIO, CHECKED);
        column->pixel2 = loadFrom(&(column->loader), input, pIO, CHECKED);
        column->pixel1 = loadFrom(&(column->loader), input, pIO, CHECKED);
        column->pixel0 = loadFrom(&(column->loader), input, pIO, CHECKED);
        init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY + 1, pIO, CHECKED);
    } else {
        init_PixelLoader(&(column->loader), sizeX, sizeY, firstX, firstY - 2, pIO, CHECKED);
        column->pixel0 = loadFrom(&(column->loader), input, pIO, CHECKED);
        column->pixel1 = loadFrom(&(column->loader), input, pIO, CHECKED);
        column->pixel2 = loadFrom(&(column->loader), input, pIO, CHECKED);
    }
}
__device__ static inline void loadAndVerticallyTransform(FDWT53 *fdwt53, FDWT53Column *column, bool CHECKED, const int *input, VerticalDWTPixelIO *pIO) {
    fdwt53->buffer.data[column->offset + 0 * fdwt53->STRIDE] = column->pixel0;
    fdwt53->buffer.data[column->offset + 1 * fdwt53->STRIDE] = column->pixel1;
    fdwt53->buffer.data[column->offset + 2 * fdwt53->STRIDE] = column->pixel2;
    for (int i = 3; i < (3 + fdwt53->WIN_SIZE_Y); i++) {
        fdwt53->buffer.data[column->offset + i * fdwt53->STRIDE] = loadFrom(&(column->loader), input, pIO, CHECKED);
    }
    column->pixel0 = fdwt53->buffer.data[column->offset + (fdwt53->WIN_SIZE_Y + 0) * fdwt53->STRIDE];
    column->pixel1 = fdwt53->buffer.data[column->offset + (fdwt53->WIN_SIZE_Y + 1) * fdwt53->STRIDE];
    column->pixel2 = fdwt53->buffer.data[column->offset + (fdwt53->WIN_SIZE_Y + 2) * fdwt53->STRIDE];
    int flag = 0; forEachVerticalOdd(&fdwt53->buffer, column->offset, flag);
    flag = 1; forEachVerticalEven(&fdwt53->buffer, column->offset, flag);
}
__device__ static inline void transform(FDWT53 *fdwt53, bool CHECK_LOADS, bool CHECK_WRITES, const int *in, int *out, int sizeX, int sizeY, int winSteps) {
    FDWT53Column column; column.CHECKED_LOADER = CHECK_LOADS;
    VerticalDWTPixelIO pIO;
    FDWT53Column boundaryColumn; boundaryColumn.CHECKED_LOADER = CHECK_LOADS;
    VerticalDWTPixelIO pIO_b;

    const int firstY = blockIdx.y * fdwt53->WIN_SIZE_Y * winSteps;
    initColumn(fdwt53, &column, CHECK_LOADS, in, sizeX, sizeY, threadIdx.x, firstY, &pIO);

    clear_FDWT53Column(&boundaryColumn, &pIO_b);
    if (threadIdx.x < 3) {
        const int colId = threadIdx.x + ((threadIdx.x == 0) ? fdwt53->WIN_SIZE_X : -3);
        initColumn(fdwt53, &boundaryColumn, CHECK_LOADS, in, sizeX, sizeY, colId, firstY, &pIO_b);
    }

    const int outColumnIndex = (threadIdx.x * 2) - (fdwt53->WIN_SIZE_X - 1) * (threadIdx.x / (fdwt53->WIN_SIZE_X / 2));
    const int outColumnOffset = getColumnOffset(outColumnIndex, &(fdwt53->buffer));
    const int outputFirstX = blockIdx.x * fdwt53->WIN_SIZE_X + outColumnIndex;

    VerticalDWTBandWriter writer; writer.CHECKED = CHECK_WRITES;
    VerticalDWTBandIO bandIO; bandIO.CHECKED = CHECK_WRITES;
    init_BandWriter(&writer, &bandIO, sizeX, sizeY, outputFirstX, firstY);

    for (int w = 0; w < winSteps; w++) {
        loadAndVerticallyTransform(fdwt53, &column, CHECK_LOADS, in, &pIO);
        if (threadIdx.x < 3) loadAndVerticallyTransform(fdwt53, &boundaryColumn, CHECK_LOADS, in, &pIO_b);
        __syncthreads();

        int flag = 0;
        forEachHorizontalOdd(&(fdwt53->buffer), 2, fdwt53->WIN_SIZE_Y, flag);
        __syncthreads();

        flag = 1;
        forEachHorizontalEven(&(fdwt53->buffer), 2, fdwt53->WIN_SIZE_Y, flag);
        __syncthreads();

        for (int r = 2; r < (2 + fdwt53->WIN_SIZE_Y); r += 2) {
            writeLowInto(&writer, &bandIO, out, &(fdwt53->buffer.data[outColumnOffset + r * fdwt53->buffer.VERTICAL_STRIDE]));
            writeHighInto(&writer, &bandIO, out, &(fdwt53->buffer.data[outColumnOffset + (r + 1) * fdwt53->buffer.VERTICAL_STRIDE]));
        }
        __syncthreads();
    }
}

__global__ void cl_fdwt53Kernel_cuda(const int *in, int *out, int sx, int sy, int steps, int WIN_SIZE_X, int WIN_SIZE_Y) {
    __shared__ FDWT53 fdwt53;
    fdwt53.WIN_SIZE_X = WIN_SIZE_X;
    fdwt53.WIN_SIZE_Y = WIN_SIZE_Y;

    for (int i = 0; i < (int)(sizeof(fdwt53.buffer.data) / sizeof(int)); i++) fdwt53.buffer.data[i] = 0;

    fdwt53.buffer.SIZE_X = fdwt53.WIN_SIZE_X;
    fdwt53.buffer.SIZE_Y = fdwt53.WIN_SIZE_Y + 3;
    fdwt53.buffer.VERTICAL_STRIDE = BOUNDARY_X + (fdwt53.buffer.SIZE_X / 2);
    fdwt53.buffer.SHM_BANKS = 32;
    fdwt53.buffer.BUFFER_SIZE = fdwt53.buffer.VERTICAL_STRIDE * fdwt53.buffer.SIZE_Y;
    fdwt53.buffer.PADDING = fdwt53.buffer.SHM_BANKS - ((fdwt53.buffer.BUFFER_SIZE + fdwt53.buffer.SHM_BANKS / 2) % fdwt53.buffer.SHM_BANKS);
    fdwt53.buffer.ODD_OFFSET = fdwt53.buffer.BUFFER_SIZE + fdwt53.buffer.PADDING;
    fdwt53.STRIDE = fdwt53.buffer.VERTICAL_STRIDE;

    const int maxX = (blockIdx.x + 1) * WIN_SIZE_X + 1;
    const int maxY = (blockIdx.y + 1) * WIN_SIZE_Y * steps + 1;
    const bool atRightBoundary = maxX >= sx;
    const bool atBottomBoundary = maxY >= sy;

    if (atBottomBoundary) transform(&fdwt53, true, true, in, out, sx, sy, steps);
    else if (atRightBoundary) transform(&fdwt53, false, true, in, out, sx, sy, steps);
    else transform(&fdwt53, false, false, in, out, sx, sy, steps);
}

static void launchFDWT53Kernel(int WIN_SX, int WIN_SY, int *in, int *out, int sx, int sy) {
    const int steps = (sy / (15 * WIN_SY)) + ((sy % (15 * WIN_SY)) ? 1 : 0);
    int gx = (sx / WIN_SX) + ((sx % WIN_SX) ? 1 : 0);
    int gy = (sy / (WIN_SY * steps)) + ((sy % (WIN_SY * steps)) ? 1 : 0);

    printf("sliding steps = %d , gx = %d , gy = %d \n", steps, gx, gy);

    dim3 block(WIN_SX, 1);
    dim3 grid(gx, gy);
    cl_fdwt53Kernel_cuda<<<grid, block>>>(in, out, sx, sy, steps, WIN_SX, WIN_SY);
    printf("kl_fdwt53Kernel in launchFDW53Kernel has finished\n");
}

namespace dwt_cuda {

void fdwt53(int *in, int *out, int sizeX, int sizeY, int levels) {
    if (sizeX >= 960) launchFDWT53Kernel(192, 8, in, out, sizeX, sizeY);
    else if (sizeX >= 480) launchFDWT53Kernel(128, 8, in, out, sizeX, sizeY);
    else launchFDWT53Kernel(64, 8, in, out, sizeX, sizeY);

    if (levels > 1) {
        const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 : 0);
        const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 : 0);
        cudaMemcpy(in, out, llSizeX * llSizeY * sizeof(int), cudaMemcpyDeviceToDevice);
        fdwt53(in, out, llSizeX, llSizeY, levels - 1);
    }
}

void rdwt53(int *in, int *out, int sizeX, int sizeY, int levels) {
    cudaMemcpy(out, in, sizeX * sizeY * sizeof(int), cudaMemcpyDeviceToDevice);
}

