template <typename T>
void processDWT(struct dwt *d, int forward, int writeVisual) {
    int componentSize = d->pixWidth * d->pixHeight * (int)sizeof(T);
    T *temp = (T*)malloc(componentSize);
    memset(temp, 0, componentSize);

    T *c_r_out = nullptr, *backup = nullptr;
    cudaMalloc(&c_r_out, componentSize);
    cudaMemcpy(c_r_out, temp, componentSize, cudaMemcpyHostToDevice);
    cudaMalloc(&backup, componentSize);
    cudaMemcpy(backup, temp, componentSize, cudaMemcpyHostToDevice);

    if (d->components == 3) {
        T *c_g_out = nullptr, *c_b_out = nullptr;
        T *c_r = nullptr, *c_g = nullptr, *c_b = nullptr;

        cudaMalloc(&c_g_out, componentSize); cudaMemcpy(c_g_out, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMalloc(&c_b_out, componentSize); cudaMemcpy(c_b_out, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMalloc(&c_r, componentSize); cudaMemcpy(c_r, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMalloc(&c_g, componentSize); cudaMemcpy(c_g, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMalloc(&c_b, componentSize); cudaMemcpy(c_b, temp, componentSize, cudaMemcpyHostToDevice);

        rgbToComponents(c_r, c_g, c_b, d->srcImg, d->pixWidth, d->pixHeight);

        nStage2dDWT(c_r, c_r_out, backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);
        nStage2dDWT(c_g, c_g_out, backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);
        nStage2dDWT(c_b, c_b_out, backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);

#ifdef OUTPUT
        if (writeVisual) {
            writeNStage2DDWT(c_r_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".r");
            writeNStage2DDWT(c_g_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".g");
            writeNStage2DDWT(c_b_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".b");
        } else {
            writeLinear(c_r_out, d->pixWidth, d->pixHeight, d->outFilename, ".r");
            writeLinear(c_g_out, d->pixWidth, d->pixHeight, d->outFilename, ".g");
            writeLinear(c_b_out, d->pixWidth, d->pixHeight, d->outFilename, ".b");
        }
#endif

        cudaFree(c_r); cudaFree(c_g); cudaFree(c_b);
        cudaFree(c_g_out); cudaFree(c_b_out);
    } else if (d->components == 1) {
        T *c_r = nullptr;
        cudaMalloc(&c_r, componentSize);
        cudaMemcpy(c_r, temp, componentSize, cudaMemcpyHostToDevice);

        bwToComponent(c_r, d->srcImg, d->pixWidth, d->pixHeight);
        nStage2dDWT(c_r, c_r_out, backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);

#ifdef OUTPUT
        if (writeVisual) writeNStage2DDWT(c_r_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".r");
        else writeLinear(c_r_out, d->pixWidth, d->pixHeight, d->outFilename, ".r");
#endif
        cudaFree(c_r);
    }

    free(temp);
    cudaFree(c_r_out);
    cudaFree(backup);
}

int main(int argc, char **argv) {
    int optindex = 0;
    char ch;
    struct option longopts[] = {
        {"dimension", required_argument, 0, 'D'},
        {"components", required_argument, 0, 'c'},
        {"depth", required_argument, 0, 'b'},
        {"level", required_argument, 0, 'l'},
        {"device", required_argument, 0, 'd'},
        {"platform", required_argument, 0, 'p'},
        {"input-dir", required_argument, 0, 'i'},
        {"forward", no_argument, 0, 'f'},
        {"reverse", no_argument, 0, 'r'},
        {"97", no_argument, 0, '9'},
        {"53", no_argument, 0, '5'},
        {"write-visual", no_argument, 0, 'w'},
        {"help", no_argument, 0, 'h'}
    };

    int pixWidth = 0, pixHeight = 0, compCount = 3, bitDepth = 8, dwtLvls = 3;
    int forward = 1, dwt97 = 0, writeVisual = 0;
    char input_dir[100] = {"."};
    char *pos = nullptr;

    while ((ch = getopt_long(argc, argv, "d:p:c:b:l:i:D:fr95wh", longopts, &optindex)) != -1) {
        switch (ch) {
            case 'D':
                pixWidth = atoi(optarg);
                pos = strstr(optarg, "x");
                if (pos == NULL || pixWidth == 0 || (strlen(pos) >= strlen(optarg))) { usage(); return -1; }
                pixHeight = atoi(pos + 1);
                break;
            case 'c': compCount = atoi(optarg); break;
            case 'b': bitDepth = atoi(optarg); break;
            case 'l': dwtLvls = atoi(optarg); break;
            case 'd': device = atoi(optarg); break;
            case 'p': platform = atoi(optarg); break;
            case 'i': strcpy(input_dir, optarg); break;
            case 'f': forward = 1; break;
            case 'r': forward = 0; break;
            case '9': dwt97 = 1; break;
            case '5': dwt97 = 0; break;
            case 'w': writeVisual = 1; break;
            case 'h': usage(); return 0;
            case '?': return -1;
            default: usage(); return -1;
        }
    }

    argc -= optind;
    argv += optind;

    if (argc == 0) { printf("Please supply src file name\n"); usage(); return -1; }
    if (pixWidth <= 0 || pixHeight <= 0) { printf("Wrong or missing dimensions\n"); usage(); return -1; }
    if (forward == 0) writeVisual = 0;

    cudaSetDevice(device);

    struct dwt *d = (struct dwt*)malloc(sizeof(struct dwt));
    d->srcImg = NULL;
    d->pixWidth = pixWidth;
    d->pixHeight = pixHeight;
    d->components = compCount;
    d->dwtLvls = dwtLvls;

    d->srcFilename = (char*)malloc(strlen(argv[0]) + 1);
    strcpy(d->srcFilename, argv[0]);
    if (argc == 1) {
        d->outFilename = (char*)malloc(strlen(d->srcFilename) + 5);
        strcpy(d->outFilename, d->srcFilename);
        strcpy(d->outFilename + strlen(d->srcFilename), ".dwt");
    } else {
        d->outFilename = strdup(argv[1]);
    }

    char real_filename[100];
    sprintf(real_filename, "%s/%s", input_dir, d->srcFilename);

    printf("\nSource file:\t\t%s\n", real_filename);
    printf(" Dimensions:\t\t%dx%d\n", pixWidth, pixHeight);
    printf(" Components count:\t%d\n", compCount);
    printf(" Bit depth:\t\t%d\n", bitDepth);
    printf(" DWT levels:\t\t%d\n", dwtLvls);
    printf(" Forward transform:\t%d\n", forward);
    printf(" 9/7 transform:\t\t%d\n", dwt97);

    int inputSize = pixWidth * pixHeight * compCount;
    d->srcImg = (unsigned char*)malloc(inputSize);
    if (getImg(real_filename, d->srcImg, inputSize) == -1) return -1;

    if (forward == 1) {
        if (dwt97 == 1) processDWT<float>(d, forward, writeVisual);
        else processDWT<int>(d, forward, writeVisual);
    } else {
        if (dwt97 == 1) processDWT<float>(d, forward, writeVisual);
        else processDWT<int>(d, forward, writeVisual);
    }

    free(d->srcFilename);
    free(d->outFilename);
    free(d->srcImg);
    free(d);
    return 0;
}

